{
    "level": "A2",
    "intro": "W tym temacie poznasz <strong>wzór strony biernej</strong>: jak powstaje V3 (imiesłów bierny), różnicę między czasownikami regularnymi i nieregularnymi oraz kolejność słów w zdaniach biernych.",
    "rules": [
        {
            "label": "Formuła",
            "color": "emerald",
            "text": "Struktura podstawowa: <strong>be + imiesłów czasu przeszłego (V3)</strong>:",
            "example": "The letter is written."
        },
        {
            "label": "Zwykła wersja V3",
            "color": "blue",
            "text": "Czasowniki regularne: <strong>V + -ed</strong>:",
            "example": "clean → cleaned, open → opened"
        },
        {
            "label": "Nieregularne V3",
            "color": "rose",
            "text": "Czasowniki nieregularne: <strong>forma specjalna</strong>:",
            "example": "write → written, make → made"
        }
    ]
}

{
    "title": "1. Wzór stanu biernego",
    "intro": "Stan pasywny tworzy się według wzoru:",
    "items": [
        {
            "label": "Być",
            "title": "Czasownik być",
            "subtitle": "Zmiany w czasie: jestem/jest/są, był/był, będzie, był..."
        },
        {
            "label": "+",
            "title": "Plus",
            "subtitle": ""
        },
        {
            "label": "V3",
            "title": "Imiesłów przeszły",
            "subtitle": "Trzecia forma czasownika: napisana, zrobiona, oczyszczona, zbudowana..."
        },
        {
            "label": "(przez)",
            "title": "Agent (opcjonalnie)",
            "subtitle": "Wykonawca akcji: przez Tomka, przez firmę..."
        }
    ]
}

{
    "title": "2. Czasowniki regularne (V3 = V2 = V + wyd.)",
    "sections": [
        {
            "label": "Podstawowa zasada",
            "color": "emerald",
            "description": "W przypadku czasowników regularnych <strong>Imiesłów bierny (V3) = Past Simple (V2)</strong>: dodaj <strong>-ed</strong>",
            "examples": [
                {
                    "en": "clean → cleaned → cleaned",
                    "ua": "Pokój jest sprzątany."
                },
                {
                    "en": "open → opened → opened",
                    "ua": "Drzwi są otwarte."
                },
                {
                    "en": "paint → painted → painted",
                    "ua": "Ściana jest pomalowana."
                }
            ]
        },
        {
            "label": "Zasady pisania – wyd",
            "color": "sky",
            "description": "Funkcje dodawania <strong>-ed</strong>:",
            "examples": [
                {
                    "en": "Після -e: live → lived",
                    "ua": "Po prostu dodaj -d"
                },
                {
                    "en": "Після приголосної + y: study → studied",
                    "ua": "y → ja + wyd"
                },
                {
                    "en": "Короткі з CVC: stop → stopped",
                    "ua": "Podwajamy ostatnią spółgłoskę"
                }
            ]
        }
    ]
}

{
    "title": "3. Czasowniki nieregularne — tabela V3",
    "intro": "Najczęstsze czasowniki nieregularne dla strony biernej:",
    "rows": [
        {
            "en": "write",
            "ua": "napisał",
            "note": "written — The letter is written."
        },
        {
            "en": "make",
            "ua": "zrobiony",
            "note": "made — Cars are made in Germany."
        },
        {
            "en": "build",
            "ua": "wybudowany",
            "note": "built — The house was built in 1990."
        },
        {
            "en": "break",
            "ua": "złamał",
            "note": "broken — The window was broken."
        },
        {
            "en": "take",
            "ua": "wziął",
            "note": "taken — The photo was taken yesterday."
        },
        {
            "en": "give",
            "ua": "dał",
            "note": "given — The prize was given to him."
        },
        {
            "en": "see",
            "ua": "piła",
            "note": "seen — The film was seen by millions."
        },
        {
            "en": "do",
            "ua": "zrobił",
            "note": "done — The work is done."
        },
        {
            "en": "send",
            "ua": "wysłano",
            "note": "sent — The email was sent."
        },
        {
            "en": "buy",
            "ua": "kupił",
            "note": "bought — The car was bought last week."
        },
        {
            "en": "sell",
            "ua": "sprzedany",
            "note": "sold — All tickets were sold."
        },
        {
            "en": "steal",
            "ua": "etola",
            "note": "stolen — My bike was stolen."
        }
    ],
    "warning": "📌 Format: <strong>V1 — V2 — V3</strong> (Bezokolicznik — Czas przeszły — Imiesłów czasu przeszłego)"
}

{
    "title": "4. Kolejność słów w stronie biernej",
    "sections": [
        {
            "label": "Twierdzący",
            "color": "emerald",
            "description": "Порядок: <strong>Temat + być + V3 (+ przez agenta)</strong>",
            "examples": [
                {
                    "en": "The letter is written.",
                    "ua": "List jest napisany."
                },
                {
                    "en": "The letter is written by Tom.",
                    "ua": "List został napisany przez Tomka."
                },
                {
                    "en": "Cars are made in Japan.",
                    "ua": "Maszyny produkowane są w Japonii."
                }
            ]
        },
        {
            "label": "Odmowa",
            "color": "rose",
            "description": "Kolejność: <strong>Temat + być + nie + V3</strong>",
            "examples": [
                {
                    "en": "The door is not locked.",
                    "ua": "Drzwi nie są zamknięte."
                },
                {
                    "en": "The work was not finished.",
                    "ua": "Praca nie została ukończona."
                }
            ]
        },
        {
            "label": "Pytanie",
            "color": "blue",
            "description": "Kolejność: <strong>Bądź + Temat + V3?</strong>",
            "examples": [
                {
                    "en": "Is the letter written?",
                    "ua": "Czy list jest napisany?"
                },
                {
                    "en": "Was the work finished?",
                    "ua": "Czy praca została ukończona?"
                },
                {
                    "en": "Are cars made here?",
                    "ua": "Czy tutaj powstają samochody?"
                }
            ]
        }
    ]
}

{
    "title": "5. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pominięcie czasownika być.",
            "wrong": "The letter written by Tom.",
            "right": "✅ The letter is written by Tom."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Używanie V2 zamiast V3.",
            "wrong": "The house was builded.",
            "right": "✅ The house was built. (build-built-built)"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Pomieszanie V2 i V3 dla nieregularnych.",
            "wrong": "The window was broke.",
            "right": "✅ The window was broken. (break-broke-broken)"
        }
    ]
}

{
    "title": "Pozostałe strony z podstawami strony biernej",
    "items": [
        {
            "label": "Co to jest głos pasywny?",
            "current": false
        },
        {
            "label": "Formularz: be + V3 (prąd)",
            "current": true
        },
        {
            "label": "Czas teraźniejszy prosty pasywny",
            "current": false
        },
        {
            "label": "Czas przeszły prosty bierny",
            "current": false
        }
    ]
}
